import{_ as a,c as d,o as r,a7 as e}from"./chunks/framework.BQb8NfN9.js";const $=JSON.parse('{"title":"全连接神经网络（FNN / FCN）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/深度学习/全连接神经网络.md","filePath":"ai/深度学习/全连接神经网络.md","lastUpdated":1773670517000}'),o={name:"ai/深度学习/全连接神经网络.md"};function n(s,t,l,i,h,p){return r(),d("div",null,t[0]||(t[0]=[e(`<h1 id="全连接神经网络-fnn-fcn" tabindex="-1">全连接神经网络（FNN / FCN） <a class="header-anchor" href="#全连接神经网络-fnn-fcn" aria-label="Permalink to &quot;全连接神经网络（FNN / FCN）&quot;">​</a></h1><p>全连接神经网络（Fully Connected Network，FCN），又称前馈神经网络（Feedforward Neural Network，FNN），是深度学习最基础的网络结构。每层的每个神经元都与上一层所有神经元相连，因此得名&quot;全连接&quot;。</p><p><strong>文档结构：</strong> 网络结构 → 激活函数 → 损失函数 → 前向传播 → 反向传播（链式法则）→ 梯度消失与爆炸 → 梯度下降 → 优化器 → 正则化 → 知识小结。</p><hr><h2 id="一、网络结构" tabindex="-1">一、网络结构 <a class="header-anchor" href="#一、网络结构" aria-label="Permalink to &quot;一、网络结构&quot;">​</a></h2><h3 id="三层组成" tabindex="-1">三层组成 <a class="header-anchor" href="#三层组成" aria-label="Permalink to &quot;三层组成&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入层          隐藏层（可多个）       输出层</span></span>
<span class="line"><span>x1 ──┐          [h1]─┐              y1</span></span>
<span class="line"><span>x2 ──┼── W1 ──→ [h2] ├── W2 ──→    y2</span></span>
<span class="line"><span>x3 ──┘          [h3]─┘              y3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><table tabindex="0"><thead><tr><th>层</th><th>作用</th></tr></thead><tbody><tr><td><strong>输入层</strong></td><td>接收原始特征 $x_1, x_2, \\ldots, x_n$</td></tr><tr><td><strong>隐藏层</strong></td><td>进行特征变换，层数越多、神经元越多，表达能力越强</td></tr><tr><td><strong>输出层</strong></td><td>输出预测结果（回归输出连续值，分类输出概率）</td></tr></tbody></table><h3 id="单个神经元的计算" tabindex="-1">单个神经元的计算 <a class="header-anchor" href="#单个神经元的计算" aria-label="Permalink to &quot;单个神经元的计算&quot;">​</a></h3><p>$$z = \\boldsymbol{w}^{\\top}\\boldsymbol{x} + b = \\sum_{i=1}^{n} w_i x_i + b$$</p><p>$$a = f(z)$$</p><p>其中 $f$ 是激活函数。<strong>增加隐藏层数、增加神经元数</strong>均可增强网络的表达能力。</p><hr><h2 id="二、激活函数" tabindex="-1">二、激活函数 <a class="header-anchor" href="#二、激活函数" aria-label="Permalink to &quot;二、激活函数&quot;">​</a></h2><p>激活函数引入<strong>非线性</strong>，没有激活函数的多层网络等价于单层线性变换，无法拟合复杂函数。</p><h3 id="_1-阶跃函数-符号函数-sign" tabindex="-1">1. 阶跃函数 / 符号函数（Sign） <a class="header-anchor" href="#_1-阶跃函数-符号函数-sign" aria-label="Permalink to &quot;1. 阶跃函数 / 符号函数（Sign）&quot;">​</a></h3><p>$$f(z) = \\begin{cases} +1 &amp; z \\geq 0 \\ -1 &amp; z &lt; 0 \\end{cases}$$</p><p><strong>值域</strong>：\${-1, +1}$；不可导，只用于感知机，深度学习中不使用。</p><h3 id="_2-sigmoid" tabindex="-1">2. Sigmoid <a class="header-anchor" href="#_2-sigmoid" aria-label="Permalink to &quot;2. Sigmoid&quot;">​</a></h3><p>$$\\sigma(z) = \\frac{1}{1 + e^{-z}}$$</p><p><strong>值域</strong>：$(0, 1)$；导数：$\\sigma&#39;(z) = \\sigma(z)(1-\\sigma(z))$，最大值为 0.25。</p><p><strong>优点</strong>：输出可解释为概率，适合二分类输出层。</p><p><strong>缺点</strong>：深层网络易发生<strong>梯度消失</strong>（导数最大仅 0.25，多层连乘趋近 0）；含指数，计算略慢。</p><h3 id="_3-tanh-双曲正切" tabindex="-1">3. Tanh（双曲正切） <a class="header-anchor" href="#_3-tanh-双曲正切" aria-label="Permalink to &quot;3. Tanh（双曲正切）&quot;">​</a></h3><p>$$\\tanh(z) = \\frac{e^z - e^{-z}}{e^z + e^{-z}}$$</p><p><strong>值域</strong>：$(-1, 1)$；导数：$\\tanh&#39;(z) = 1 - \\tanh^2(z)$，最大值为 1。</p><p><strong>优点</strong>：零中心化（均值为 0），比 Sigmoid 收敛快。</p><p><strong>缺点</strong>：仍存在梯度消失问题。</p><h3 id="_4-relu-rectified-linear-unit" tabindex="-1">4. ReLU（Rectified Linear Unit） <a class="header-anchor" href="#_4-relu-rectified-linear-unit" aria-label="Permalink to &quot;4. ReLU（Rectified Linear Unit）&quot;">​</a></h3><p>$$f(z) = \\max(0, z) = \\begin{cases} z &amp; z &gt; 0 \\ 0 &amp; z \\leq 0 \\end{cases}$$</p><p><strong>值域</strong>：$[0, +\\infty)$；导数：$z&gt;0$ 时为 1，$z\\leq0$ 时为 0。</p><p><strong>优点</strong>：计算简单；正区间梯度为 1，缓解梯度消失；收敛快。</p><p><strong>缺点</strong>：<strong>&quot;死亡 ReLU&quot;</strong> 问题——负区间梯度恒为 0，神经元可能永久失活。</p><h3 id="_5-swish" tabindex="-1">5. Swish <a class="header-anchor" href="#_5-swish" aria-label="Permalink to &quot;5. Swish&quot;">​</a></h3><p>$$f(z) = z \\cdot \\sigma(z) = \\frac{z}{1 + e^{-z}}$$</p><p><strong>优点</strong>：平滑、非单调；在深层网络（如 EfficientNet）中表现优于 ReLU。</p><h3 id="_6-softmax-多分类输出层" tabindex="-1">6. Softmax（多分类输出层） <a class="header-anchor" href="#_6-softmax-多分类输出层" aria-label="Permalink to &quot;6. Softmax（多分类输出层）&quot;">​</a></h3><p>$$\\text{Softmax}(z_k) = \\frac{e^{z_k}}{\\sum_{j=1}^{K} e^{z_j}}$$</p><p><strong>值域</strong>：每个输出在 $(0,1)$ 且所有输出之和为 1，可解释为各类别概率。只用于多分类输出层。</p><h3 id="激活函数对比" tabindex="-1">激活函数对比 <a class="header-anchor" href="#激活函数对比" aria-label="Permalink to &quot;激活函数对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>函数</th><th>值域</th><th>梯度消失</th><th>适用场景</th></tr></thead><tbody><tr><td>Sign</td><td>\${-1,+1}$</td><td>不适用</td><td>感知机</td></tr><tr><td>Sigmoid</td><td>$(0,1)$</td><td>严重</td><td>二分类输出层</td></tr><tr><td>Tanh</td><td>$(-1,1)$</td><td>较重</td><td>隐藏层（浅层）</td></tr><tr><td>ReLU</td><td>$[0,+\\infty)$</td><td>轻微</td><td>隐藏层（首选）</td></tr><tr><td>Swish</td><td>$\\approx(-0.28,+\\infty)$</td><td>极轻</td><td>深层网络</td></tr><tr><td>Softmax</td><td>$(0,1)$，和为 1</td><td>不适用</td><td>多分类输出层</td></tr></tbody></table><hr><h2 id="三、损失函数" tabindex="-1">三、损失函数 <a class="header-anchor" href="#三、损失函数" aria-label="Permalink to &quot;三、损失函数&quot;">​</a></h2><p>衡量预测值与真实值之间的差距，是训练的优化目标。</p><h3 id="_1-均方误差-mse-——-回归任务" tabindex="-1">1. 均方误差（MSE）—— 回归任务 <a class="header-anchor" href="#_1-均方误差-mse-——-回归任务" aria-label="Permalink to &quot;1. 均方误差（MSE）—— 回归任务&quot;">​</a></h3><p>$$\\mathcal{L} = \\frac{1}{n}\\sum_{i=1}^{n}(\\hat{y}_i - y_i)^2$$</p><p>对大误差惩罚强（平方放大）；对异常值敏感。</p><h3 id="_2-交叉熵损失-cross-entropy-——-分类任务" tabindex="-1">2. 交叉熵损失（Cross-Entropy）—— 分类任务 <a class="header-anchor" href="#_2-交叉熵损失-cross-entropy-——-分类任务" aria-label="Permalink to &quot;2. 交叉熵损失（Cross-Entropy）—— 分类任务&quot;">​</a></h3><p><strong>二分类：</strong></p><p>$$\\mathcal{L} = -\\frac{1}{n}\\sum_{i=1}^{n}\\big[y_i\\log\\hat{y}_i + (1-y_i)\\log(1-\\hat{y}_i)\\big]$$</p><p><strong>多分类（配合 Softmax）：</strong></p><p>$$\\mathcal{L} = -\\frac{1}{n}\\sum_{i=1}^{n}\\sum_{k=1}^{K} y_{ik}\\log\\hat{y}_{ik}$$</p><p>凸函数，由最大似然推导而来，梯度计算简洁。</p><h3 id="选择建议" tabindex="-1">选择建议 <a class="header-anchor" href="#选择建议" aria-label="Permalink to &quot;选择建议&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任务类型</th><th>输出激活</th><th>损失函数</th></tr></thead><tbody><tr><td>回归</td><td>线性（无激活）</td><td>MSE</td></tr><tr><td>二分类</td><td>Sigmoid</td><td>二分类交叉熵</td></tr><tr><td>多分类</td><td>Softmax</td><td>多分类交叉熵</td></tr></tbody></table><hr><h2 id="四、前向传播-forward-pass" tabindex="-1">四、前向传播（Forward Pass） <a class="header-anchor" href="#四、前向传播-forward-pass" aria-label="Permalink to &quot;四、前向传播（Forward Pass）&quot;">​</a></h2><p>前向传播是将输入数据沿网络依次计算，得到最终预测值的过程。</p><p><strong>以两层网络（输入→隐藏→输出）为例：</strong></p><p>$$\\boldsymbol{z}^{(1)} = \\boldsymbol{W}^{(1)}\\boldsymbol{x} + \\boldsymbol{b}^{(1)}$$</p><p>$$\\boldsymbol{a}^{(1)} = f(\\boldsymbol{z}^{(1)})$$</p><p>$$\\boldsymbol{z}^{(2)} = \\boldsymbol{W}^{(2)}\\boldsymbol{a}^{(1)} + \\boldsymbol{b}^{(2)}$$</p><p>$$\\hat{\\boldsymbol{y}} = g(\\boldsymbol{z}^{(2)})$$</p><p>其中 $f$ 是隐藏层激活函数，$g$ 是输出层激活函数（如 Softmax）。前向传播结束后计算损失 $\\mathcal{L}(\\hat{\\boldsymbol{y}}, \\boldsymbol{y})$。</p><hr><h2 id="五、反向传播-backpropagation" tabindex="-1">五、反向传播（Backpropagation） <a class="header-anchor" href="#五、反向传播-backpropagation" aria-label="Permalink to &quot;五、反向传播（Backpropagation）&quot;">​</a></h2><p>反向传播利用<strong>链式法则</strong>，从损失函数出发，逐层计算每个参数对损失的梯度，再用梯度下降更新参数。</p><h3 id="链式法则" tabindex="-1">链式法则 <a class="header-anchor" href="#链式法则" aria-label="Permalink to &quot;链式法则&quot;">​</a></h3><p>复合函数 $z = f(g(x))$ 的导数：</p><p>$$\\frac{dz}{dx} = \\frac{dz}{dy} \\cdot \\frac{dy}{dx}, \\quad y = g(x)$$</p><h3 id="反向传播流程" tabindex="-1">反向传播流程 <a class="header-anchor" href="#反向传播流程" aria-label="Permalink to &quot;反向传播流程&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 前向传播，保存每层的 z 和 a</span></span>
<span class="line"><span>② 计算输出层对损失的梯度 dL/dz_out</span></span>
<span class="line"><span>③ 逐层向后（链式法则）：</span></span>
<span class="line"><span>   dL/dW = dL/dz · a_prev（权重梯度）</span></span>
<span class="line"><span>   dL/db = dL/dz（偏置梯度）</span></span>
<span class="line"><span>   dL/da_prev = dL/dz · W（传给上一层）</span></span>
<span class="line"><span>④ 更新参数：W := W - α * dL/dW</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="六、梯度消失与梯度爆炸" tabindex="-1">六、梯度消失与梯度爆炸 <a class="header-anchor" href="#六、梯度消失与梯度爆炸" aria-label="Permalink to &quot;六、梯度消失与梯度爆炸&quot;">​</a></h2><h3 id="梯度消失-vanishing-gradient" tabindex="-1">梯度消失（Vanishing Gradient） <a class="header-anchor" href="#梯度消失-vanishing-gradient" aria-label="Permalink to &quot;梯度消失（Vanishing Gradient）&quot;">​</a></h3><p><strong>原因</strong>：链式求导时，若每层激活函数的梯度 $\\lvert\\partial a/\\partial z\\rvert &lt; 1$（如 Sigmoid 最大 0.25），多层连乘后梯度指数级缩小，前层参数几乎不更新。</p><p><strong>解决方案：</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>原理</th></tr></thead><tbody><tr><td>使用 ReLU / Swish</td><td>正区间梯度为 1，不衰减</td></tr><tr><td>Batch Normalization</td><td>归一化每层激活，稳定梯度</td></tr><tr><td>残差连接（ResNet）</td><td>梯度可直接跳过若干层流动</td></tr><tr><td>LSTM / GRU</td><td>门控机制保留远距离梯度信息</td></tr></tbody></table><h3 id="梯度爆炸-exploding-gradient" tabindex="-1">梯度爆炸（Exploding Gradient） <a class="header-anchor" href="#梯度爆炸-exploding-gradient" aria-label="Permalink to &quot;梯度爆炸（Exploding Gradient）&quot;">​</a></h3><p><strong>原因</strong>：权重较大时，链式乘积指数级增大，参数更新量过大导致不收敛。</p><p><strong>解决方案：</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>原理</th></tr></thead><tbody><tr><td>梯度裁剪（Gradient Clipping）</td><td>超过阈值时按比例缩放：$g \\leftarrow g \\cdot \\frac{c}{\\lVert g\\rVert}$</td></tr><tr><td>权重正则化（L1/L2）</td><td>惩罚过大的权重值</td></tr><tr><td>He / Xavier 初始化</td><td>控制初始梯度规模</td></tr></tbody></table><hr><h2 id="七、梯度下降算法" tabindex="-1">七、梯度下降算法 <a class="header-anchor" href="#七、梯度下降算法" aria-label="Permalink to &quot;七、梯度下降算法&quot;">​</a></h2><p><strong>目标</strong>：找到最优参数 $\\boldsymbol{w}^*$，使损失函数 $\\mathcal{L}$ 最小。</p><p>$$\\boldsymbol{w} \\leftarrow \\boldsymbol{w} - \\alpha \\nabla_{\\boldsymbol{w}} \\mathcal{L}$$</p><h3 id="三种变体" tabindex="-1">三种变体 <a class="header-anchor" href="#三种变体" aria-label="Permalink to &quot;三种变体&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>每次使用样本数</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>批量梯度下降 BGD</td><td>全部 $n$ 个</td><td>稳定，可收敛到全局</td><td>每步计算量大，慢</td></tr><tr><td>随机梯度下降 SGD</td><td>1 个</td><td>快，可跳出局部最优</td><td>噪声大，不稳定</td></tr><tr><td>小批量 Mini-batch GD</td><td>$b$ 个（如 32/64/128）</td><td>折中，GPU 并行友好</td><td>需调 batch size</td></tr></tbody></table><p>实际训练中几乎都用 <strong>Mini-batch GD</strong>。</p><hr><h2 id="八、优化器" tabindex="-1">八、优化器 <a class="header-anchor" href="#八、优化器" aria-label="Permalink to &quot;八、优化器&quot;">​</a></h2><p>优化器在梯度下降基础上改进，加快收敛、提高稳定性。</p><h3 id="_1-标准-sgd" tabindex="-1">1. 标准 SGD <a class="header-anchor" href="#_1-标准-sgd" aria-label="Permalink to &quot;1. 标准 SGD&quot;">​</a></h3><p>$$\\boldsymbol{w} \\leftarrow \\boldsymbol{w} - \\alpha \\boldsymbol{g}$$</p><p>缺点：学习率固定，平坦区域收敛慢，峡谷区域震荡。</p><h3 id="_2-动量优化器-momentum" tabindex="-1">2. 动量优化器（Momentum） <a class="header-anchor" href="#_2-动量优化器-momentum" aria-label="Permalink to &quot;2. 动量优化器（Momentum）&quot;">​</a></h3><p>积累历史梯度方向：</p><p>$$\\boldsymbol{v} \\leftarrow \\beta \\boldsymbol{v} - \\alpha \\boldsymbol{g}, \\quad \\boldsymbol{w} \\leftarrow \\boldsymbol{w} + \\boldsymbol{v}$$</p><ul><li>$\\beta$（动量系数，常取 0.9）：历史方向保留比例。</li><li><strong>优点</strong>：梯度稳定方向越来越快；有助于跳出局部极值。</li><li><strong>缺点</strong>：需手动设置学习率和动量系数。</li></ul><h3 id="_3-adagrad" tabindex="-1">3. Adagrad <a class="header-anchor" href="#_3-adagrad" aria-label="Permalink to &quot;3. Adagrad&quot;">​</a></h3><p>对不同参数自适应学习率，历史梯度大的参数学习率小：</p><p>$$G \\leftarrow G + g^2, \\quad w \\leftarrow w - \\frac{\\alpha}{\\sqrt{G + \\varepsilon}} g$$</p><ul><li><strong>优点</strong>：自适应学习率；对稀疏特征（如 NLP 词嵌入）友好。</li><li><strong>缺点</strong>：$G$ 单调递增，学习率最终趋近 0，训练后期失效。</li></ul><h3 id="_4-rmsprop" tabindex="-1">4. RMSprop <a class="header-anchor" href="#_4-rmsprop" aria-label="Permalink to &quot;4. RMSprop&quot;">​</a></h3><p>对 Adagrad 改进，引入指数加权移动平均：</p><p>$$G \\leftarrow \\rho G + (1-\\rho) g^2, \\quad w \\leftarrow w - \\frac{\\alpha}{\\sqrt{G + \\varepsilon}} g$$</p><ul><li>$\\rho$ 常取 0.9；对 RNN 效果好。</li><li><strong>优点</strong>：解决 Adagrad 学习率消失；适合非平稳目标。</li></ul><h3 id="_5-adam-自适应矩估计" tabindex="-1">5. Adam（自适应矩估计） <a class="header-anchor" href="#_5-adam-自适应矩估计" aria-label="Permalink to &quot;5. Adam（自适应矩估计）&quot;">​</a></h3><p>同时维护一阶矩（梯度均值）和二阶矩（梯度方差）：</p><p>$$m \\leftarrow \\beta_1 m + (1-\\beta_1) g$$</p><p>$$v \\leftarrow \\beta_2 v + (1-\\beta_2) g^2$$</p><p>偏差修正（补偿初始化为 0 的偏差）：</p><p>$$\\hat{m} = \\frac{m}{1-\\beta_1^t}, \\quad \\hat{v} = \\frac{v}{1-\\beta_2^t}$$</p><p>参数更新：</p><p>$$w \\leftarrow w - \\frac{\\alpha}{\\sqrt{\\hat{v}} + \\varepsilon} \\hat{m}$$</p><ul><li>默认：$\\beta_1=0.9$，$\\beta_2=0.999$，$\\varepsilon=10^{-8}$，$\\alpha=10^{-3}$。</li><li><strong>优点</strong>：收敛快，对超参数不敏感，适合大多数场景。</li></ul><h3 id="优化器对比" tabindex="-1">优化器对比 <a class="header-anchor" href="#优化器对比" aria-label="Permalink to &quot;优化器对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优化器</th><th>自适应学习率</th><th>动量</th><th>推荐场景</th></tr></thead><tbody><tr><td>SGD</td><td>否</td><td>否</td><td>简单任务</td></tr><tr><td>Momentum</td><td>否</td><td>是</td><td>需要加速的场景</td></tr><tr><td>Adagrad</td><td>是</td><td>否</td><td>稀疏特征（词嵌入）</td></tr><tr><td>RMSprop</td><td>是</td><td>否</td><td>RNN / 非平稳目标</td></tr><tr><td>Adam</td><td>是</td><td>是</td><td>大多数深度学习任务（默认首选）</td></tr></tbody></table><hr><h2 id="九、正则化" tabindex="-1">九、正则化 <a class="header-anchor" href="#九、正则化" aria-label="Permalink to &quot;九、正则化&quot;">​</a></h2><p>防止<strong>过拟合</strong>的关键手段，通过约束模型复杂度提升泛化能力。</p><h3 id="过拟合-vs-欠拟合" tabindex="-1">过拟合 vs 欠拟合 <a class="header-anchor" href="#过拟合-vs-欠拟合" aria-label="Permalink to &quot;过拟合 vs 欠拟合&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>表现</th><th>原因</th><th>解决</th></tr></thead><tbody><tr><td>欠拟合</td><td>训练/测试误差都大</td><td>模型太简单</td><td>增加层数、神经元；减小正则化强度</td></tr><tr><td>过拟合</td><td>训练误差小、测试误差大</td><td>模型太复杂或数据太少</td><td>正则化、Dropout、数据增强、早停</td></tr></tbody></table><h3 id="常见正则化方法" tabindex="-1">常见正则化方法 <a class="header-anchor" href="#常见正则化方法" aria-label="Permalink to &quot;常见正则化方法&quot;">​</a></h3><p><strong>1. L2 正则化（权重衰减，Ridge）：</strong></p><p>$$\\mathcal{L}_{total} = \\mathcal{L} + \\frac{\\lambda}{2n}\\sum_j w_j^2$$</p><p>权重更新多了衰减项：$w \\leftarrow w(1 - \\alpha\\lambda/n) - \\alpha\\partial\\mathcal{L}/\\partial w$。使权重趋于小值但不为 0。</p><p><strong>2. L1 正则化（Lasso）：</strong></p><p>$$\\mathcal{L}_{total} = \\mathcal{L} + \\frac{\\lambda}{n}\\sum_j \\lvert w_j\\rvert$$</p><p>产生稀疏解（部分权重恰好为 0），等效于特征选择。</p><p><strong>3. Dropout：</strong></p><p>训练时随机将神经元输出置为 0（丢弃概率 $p$），预测时乘以 $(1-p)$ 缩放。等效于集成大量子网络，隐藏层常用 $p=0.5$。</p><p><strong>4. Batch Normalization（BN）：</strong></p><p>对每个 mini-batch 的激活值归一化（均值为 0、方差为 1），再通过可学习的 $\\gamma, \\beta$ 缩放：</p><p>$$\\hat{z} = \\frac{z - \\mu_B}{\\sqrt{\\sigma_B^2 + \\varepsilon}}, \\quad a = \\gamma\\hat{z} + \\beta$$</p><p>效果：稳定训练；支持更大学习率；有正则化效果（可少用 Dropout）。</p><p><strong>5. 早停（Early Stopping）：</strong></p><p>监控验证集损失，不再下降时提前结束训练，避免继续过拟合。</p><hr><h2 id="十、知识小结" tabindex="-1">十、知识小结 <a class="header-anchor" href="#十、知识小结" aria-label="Permalink to &quot;十、知识小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>核心内容</th><th>考试重点/易混淆点</th><th>难度</th></tr></thead><tbody><tr><td>网络结构</td><td>输入层→隐藏层→输出层；全连接即每层所有神经元相互相连</td><td>与卷积等稀疏连接区别</td><td>⭐</td></tr><tr><td>激活函数</td><td>引入非线性；ReLU 是隐藏层首选；Softmax 用于多分类输出</td><td>Sigmoid/Tanh 易梯度消失</td><td>⭐⭐</td></tr><tr><td>损失函数</td><td>回归用 MSE，分类用交叉熵</td><td>损失函数（优化）vs 评估指标</td><td>⭐⭐</td></tr><tr><td>前向传播</td><td>从输入逐层算到输出；保存中间值供反向用</td><td>矩阵乘法 + 激活顺序</td><td>⭐⭐</td></tr><tr><td>反向传播</td><td>链式法则逐层求梯度；从输出层向输入层反推</td><td>为什么保存前向中间值</td><td>⭐⭐⭐</td></tr><tr><td>梯度消失</td><td>多层 Sigmoid 乘积趋零；解决：ReLU、BN、残差连接</td><td>权重小于 1 时连乘趋零</td><td>⭐⭐⭐</td></tr><tr><td>梯度爆炸</td><td>权重大时连乘梯度过大；解决：梯度裁剪、正则化</td><td>梯度裁剪公式</td><td>⭐⭐⭐</td></tr><tr><td>优化器</td><td>Adam 综合动量 + 自适应，实践中默认首选</td><td>Adam 的 $\\beta_1, \\beta_2$ 含义</td><td>⭐⭐⭐</td></tr><tr><td>正则化</td><td>L1/L2/Dropout/BN/早停；L1 稀疏，L2 平滑</td><td>过拟合四步排查</td><td>⭐⭐⭐</td></tr></tbody></table>`,141)]))}const m=a(o,[["render",n]]);export{$ as __pageData,m as default};
